  ('elementary-8b44517b-moex-00259', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '就職場哺（集）乳之保護制度，下列敘述何者錯誤？', '["勞動基準法第52條規定，雇主應給予哺乳時間，所謂哺乳限於餵哺母乳，如事業單位內設有哺育設施， 勞工宜儘量使用之", "依性別平等工作法規定，僱用受僱者1百人以上之雇主，應提供哺（集）乳室", "依性別平等工作法規定，親自哺乳亦不限於女性受僱者，男性受僱者如有親自哺餵之需要，也可請求給 予哺乳時間", "依性別平等工作法規定，受僱者於每日正常工作時間以外之延長工作時間達 1 小時以上者，雇主應另 外給予哺（集）乳時間30分鐘"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "664e5dd214da", "answer_pdf_sha1": "920fc8b6abca", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00260', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '在團體協約約款中當事團體相互約定雇主要僱用勞工只限於可以僱用具其工會會員資格的勞工，這種約 款一般稱為：', '["封閉工廠條款", "自營商條款", "代理工廠條款", "黃狗契約條款"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "664e5dd214da", "answer_pdf_sha1": "920fc8b6abca", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00261', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '依勞動基準法，下列雇主與員工間約定有效之離職後競業禁止協議之敘述，何者正確？', '["雇主與員工間之離職後競業禁止協議期間最長為5年，約定超過5年者，強制縮短為5年", "雇主與員工間之離職後競業禁止協議之每月合理補償金額，是以每月不低於員工在職期間 1 個月平均 工資之金額補償之", "在經綜合考量補償金額足以維持勞工離職後競業禁止期間之生活所需、補償金額與勞工遵守競業禁止 之期間、區域、職業活動範圍及就業對象之範疇所受損失相當、其他與判斷補償基準合理性有關之事項 後，約定每月補償金額為不低於勞工離職時1個月平均工資百分之五十", "離職後競業禁止協議，不以書面簽署為必要"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "664e5dd214da", "answer_pdf_sha1": "920fc8b6abca", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
